35→export function useAgents(): UseAgentsReturn {
36→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
37→  const [agents, setAgents] = useState<AgentListItem[]>([]);
38→  const [isLoading, setIsLoading] = useState(false);
39→  const [error, setError] = useState<string | undefined>();
40→
41→  const fetchAgents = useCallback(async () => {
42→    if (!workspaceId) return;
43→
44→    setIsLoading(true);
45→    setError(undefined);
46→
47→    try {
48→      const url = buildAgentsUrl(workspaceId);
49→      const response = await fetch(url);
50→      if (!response.ok) {
51→        const body = await response.text();
52→        throw new Error(body);
53→      }
54→      const data = (await response.json()) as { agents: AgentListItem[] };
55→      setAgents(data.agents);
56→    } catch (err) {
57→      setError(err instanceof Error ? err.message : "Failed to load agents");
58→    } finally {
59→      setIsLoading(false);
60→    }
61→  }, [workspaceId]);
62→
63→  useEffect(() => {
64→    if (!workspaceId) return;
65→    void fetchAgents();
66→  }, [workspaceId, fetchAgents]);
67→
68→  const refresh = useCallback(() => {
69→    void fetchAgents();
70→  }, [fetchAgents]);
71→
72→  return { agents, isLoading, error, refresh };
73→}
