422→// ---------------------------------------------------------------------------
423→// Delete agent (atomic transaction)
424→// ---------------------------------------------------------------------------
425→
426→/**
427→ * Delete an agent and all associated records atomically.
428→ *
429→ * Validates:
430→ * - Agent exists in workspace
431→ * - Agent is not a brain-managed agent
432→ * - Confirmation name matches agent name
433→ *
434→ * Deletes:
435→ * 1. authorized_to edges from identity
436→ * 2. proxy_token records for identity
437→ * 3. member_of edges from identity to workspace
438→ * 4. identity_agent edges to agent
439→ * 5. identity record
440→ * 6. agent record
441→ */
442→export async function deleteAgentTransaction(
443→  surreal: Surreal,
444→  workspaceId: string,
445→  agentId: string,
446→  confirmName: string,
447→): Promise<DeleteAgentResult> {
448→  const workspaceRecord = new RecordId("workspace", workspaceId);
449→  const agentRecord = new RecordId("agent", agentId);
450→
451→  // Validate agent exists and fetch identity
452→  const [agentRows, identityRows] = await surreal
453→    .query<[
454→      Array<{ id: RecordId; name: string; runtime: string }>,
455→      Array<{ id: RecordId<"identity", string> }>,
456→    ]>(
457→      `SELECT id, name, runtime FROM $agent;
458→
459→       SELECT VALUE in FROM identity_agent
460→       WHERE out = $agent
461→       AND in IN (
462→         SELECT VALUE in FROM member_of WHERE out = $ws AND in.type = 'agent'
463→       )
464→       LIMIT 1;`,
465→      { agent: agentRecord, ws: workspaceRecord },
466→    );
467→
468→  if (agentRows.length === 0) {
469→    throw new HttpError(404, "Agent not found");
470→  }
471→
472→  const agent = agentRows[0];
473→
474→  if (agent.runtime === "brain") {
475→    throw new HttpError(403, "Cannot delete brain-managed agents");
476→  }
477→
478→  if (agent.name !== confirmName) {
479→    throw new HttpError(
480→      400,
481→      `Confirmation name '${confirmName}' does not match agent name '${agent.name}'`,
482→    );
483→  }
484→
485→  if (identityRows.length === 0) {
486→    throw new HttpError(404, "Agent identity not found in workspace");
487→  }
488→
489→  const identityRecord = identityRows[0] as unknown as RecordId<"identity", string>;
490→
491→  // Execute deletion in a single transaction
492→  await surreal.query(
493→    `BEGIN TRANSACTION;
494→     DELETE FROM authorized_to WHERE in = $identity;
495→     DELETE FROM proxy_token WHERE identity = $identity;
496→     DELETE FROM member_of WHERE in = $identity AND out = $ws;
497→     DELETE FROM identity_agent WHERE out = $agent;
498→     DELETE $identity;
499→     DELETE $agent;
500→     COMMIT TRANSACTION;`,
501→    {
502→      identity: identityRecord,
503→      agent: agentRecord,
504→      ws: workspaceRecord,
505→    },
506→  );
507→
508→  return {
509→    deleted: true,
510→    sessions_aborted: 0, // Deferred to R2
511→  };
512→}
