111→async function handleListAgents(
112→  deps: ServerDependencies,
113→  workspaceId: string,
114→  request: Request,
115→): Promise<Response> {
116→  const identityOrError = await resolveIdentityFromSession(deps, request);
117→  if (isResponse(identityOrError)) return identityOrError;
118→
119→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "agent.list.workspace_resolve.failed");
120→  if (isResponse(workspaceOrError)) return workspaceOrError;
121→
122→  try {
123→    const agents = await listAgents(deps.surreal, workspaceId);
124→    trace.getActiveSpan()?.setAttribute("agent.list.count", agents.length);
125→    return jsonResponse({ agents }, 200);
126→  } catch (error) {
127→    log.error("agent.list.failed", "Failed to list agents", error, { workspaceId });
128→    return jsonError("failed to list agents", 500);
129→  }
