132→// ---------------------------------------------------------------------------
133→// POST /api/workspaces/:workspaceId/agents
134→// ---------------------------------------------------------------------------
135→
136→async function handleCreateAgent(
137→  deps: ServerDependencies,
138→  workspaceId: string,
139→  request: Request,
140→): Promise<Response> {
141→  const identityOrError = await resolveIdentityFromSession(deps, request);
142→  if (isResponse(identityOrError)) return identityOrError;
143→
144→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "agent.create.workspace_resolve.failed");
145→  if (isResponse(workspaceOrError)) return workspaceOrError;
146→
147→  let body: Record<string, unknown>;
148→  try {
149→    body = await request.json() as Record<string, unknown>;
150→  } catch {
151→    return jsonError("invalid JSON body", 400);
152→  }
153→
154→  // Validate name
155→  const name = body.name;
156→  if (typeof name !== "string" || name.trim().length === 0) {
157→    return jsonError("name_required", 400);
158→  }
159→
160→  // Validate runtime
161→  const runtime = body.runtime;
162→  if (!isValidRuntime(runtime)) {
163→    return jsonError("invalid_runtime", 400);
164→  }
165→
166→  // Sandbox-specific validation
167→  if (runtime === "sandbox") {
168→    // Check workspace has sandbox_provider configured
169→    const [wsRows] = await deps.surreal.query<[Array<{ settings: { sandbox_provider?: string } }>]>(
170→      "SELECT settings FROM $ws;",
171→      { ws: new RecordId("workspace", workspaceId) },
172→    );
173→    const sandboxProvider = wsRows[0]?.settings?.sandbox_provider;
174→    if (!sandboxProvider) {
175→      return jsonError("sandbox_provider_not_configured", 400);
176→    }
177→
178→    // Local provider cannot use image or snapshot
179→    if (sandboxProvider === "local") {
180→      const sandboxConfig = body.sandbox_config as { image?: string; snapshot?: string } | undefined;
181→      if (sandboxConfig?.image || sandboxConfig?.snapshot) {
182→        return jsonError("invalid_sandbox_config", 400);
183→      }
184→    }
185→  }
186→
187→  const input: CreateAgentInput = {
188→    name: name.trim(),
189→    runtime,
190→    ...(body.description && typeof body.description === "string" ? { description: body.description } : {}),
191→    ...(body.model && typeof body.model === "string" ? { model: body.model } : {}),
192→    ...(body.sandbox_config ? { sandbox_config: body.sandbox_config as CreateAgentInput["sandbox_config"] } : {}),
193→    ...(body.authority_scopes ? { authority_scopes: body.authority_scopes as CreateAgentInput["authority_scopes"] } : {}),
194→  };
195→
196→  try {
197→    const result = await createAgentTransaction(deps.surreal, workspaceId, input, new Date());
198→    trace.getActiveSpan()?.setAttribute("agent.create.agent_id", result.agent.id);
199→    trace.getActiveSpan()?.setAttribute("agent.create.runtime", runtime);
200→    return jsonResponse(
201→      {
202→        agent: result.agent,
203→        ...(result.proxy_token ? { proxy_token: result.proxy_token } : {}),
204→        workspace_id: workspaceId,
205→      },
206→      201,
207→    );
208→  } catch (error) {
209→    if (error instanceof HttpError) {
210→      return jsonError(
211→        error.status === 409 ? "agent_name_not_unique" : error.message,
212→        error.status,
213→      );
214→    }
215→    log.error("agent.create.failed", "Failed to create agent", error, { workspaceId });
216→    return jsonError("failed to create agent", 500);
217→  }
218→}
