  1→import { afterAll, beforeAll, describe, expect, it } from "bun:test";
  2→import { randomUUID } from "node:crypto";
  3→import { RecordId, Surreal } from "surrealdb";
  4→import { applyTestSchema } from "../acceptance-test-kit";
  5→import { checkAuthority } from "../../../app/src/server/iam/authority";
  6→
  7→/**
  8→ * US-UI-03-01: Role-based authority with per-identity overrides
  9→ *
 10→ * Resolution order: per-identity override -> role default -> agent_type default -> blocked
 11→ * Human identities bypass authority checks entirely.
 12→ * Per-identity authorized_to override takes precedence over role-based authority_scope.
 13→ */
 14→
 15→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 16→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 17→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 18→
 19→let surreal: Surreal;
 20→let namespace: string;
 21→let database: string;
 22→let workspaceRecord: RecordId<"workspace", string>;
 23→
 24→beforeAll(async () => {
 25→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 26→  namespace = `smoke_authority_${runId}`;
 27→  database = `authority_${Math.floor(Math.random() * 100000)}`;
 28→
 29→  surreal = new Surreal();
 30→  await surreal.connect(surrealUrl);
 31→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 32→  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
 33→  await surreal.use({ namespace });
 34→  await surreal.query(`DEFINE DATABASE ${database};`);
 35→  await surreal.use({ namespace, database });
 36→
 37→  await applyTestSchema(surreal);
 38→
 39→  const now = new Date();
 40→  workspaceRecord = new RecordId("workspace", randomUUID());
 41→  await surreal.create(workspaceRecord).content({
 42→    name: "Authority Test Workspace",
 43→    status: "active",
 44→    onboarding_complete: true,
 45→    onboarding_turn_count: 0,
 46→    onboarding_summary_pending: false,
 47→    onboarding_started_at: now,
 48→    created_at: now,
 49→  });
 50→}, 60_000);
 51→
 52→afterAll(async () => {
 53→  if (!surreal) return;
 54→  try {
 55→    await surreal.query(`REMOVE DATABASE ${database};`);
 56→    await surreal.query(`REMOVE NAMESPACE ${namespace};`);
 57→  } catch {}
 58→  await surreal.close().catch(() => {});
 59→}, 10_000);
 60→
 61→// -- Helpers --
 62→
 63→async function createIdentity(
