}

// ---------------------------------------------------------------------------
// Feed Stream Helpers
// ---------------------------------------------------------------------------

/**
 * Opens an SSE connection to the governance feed stream for a workspace.
 * Returns a controller that can collect events and close the connection.
 */
export function openFeedStream(
  baseUrl: string,
  workspaceId: string,
  user: TestUser,
  options?: { lastEventId?: string },
): FeedStreamController {
  return new FeedStreamController(baseUrl, workspaceId, user, options);
}

export class FeedStreamController {
  private events: FeedStreamEvent[] = [];
  private rawEvents: string[] = [];
  private reader: ReadableStreamDefaultReader<Uint8Array> | undefined;
  private abortController = new AbortController();
  private buffer = "";
  private decoder = new TextDecoder();
  private connected = false;
  private connectionPromise: Promise<void> | undefined;
  private lastEventId: string | undefined;

  constructor(
    private baseUrl: string,
    private workspaceId: string,
    private user: TestUser,
    private options?: { lastEventId?: string },
  ) {
    this.lastEventId = options?.lastEventId;
  }

  /** Start listening for SSE events. */
  async connect(): Promise<void> {
    this.connectionPromise = this._connect();
    // Give the connection a moment to establish
    await new Promise((resolve) => setTimeout(resolve, 200));
  }

  /** Get the last event ID received from the server. */
  getLastEventId(): string | undefined {
    return this.lastEventId;
  }

  private async _connect(): Promise<void> {
    const url = `${this.baseUrl}/api/workspaces/${this.workspaceId}/feed/stream`;
    const headers: Record<string, string> = {
      Accept: "text/event-stream",
      ...this.user.headers,
    };
    if (this.lastEventId) {
      headers["Last-Event-ID"] = this.lastEventId;
    }
    const response = await fetch(url, {
      headers,
      signal: this.abortController.signal,
    });

    if (!response.ok || !response.body) {
      throw new Error(`Failed to open feed stream (${response.status})`);
    }

    this.connected = true;
    this.reader = response.body.getReader();

    try {
      while (true) {
        const { value, done } = await this.reader.read();
        if (done) break;

        this.buffer += this.decoder.decode(value, { stream: true });
        const segments = this.buffer.split("\n\n");
        this.buffer = segments.pop() ?? "";

        for (const segment of segments) {
          const lines = segment.split("\n");
          const idLine = lines.find((line) => line.startsWith("id: "));
          const dataLine = lines.find((line) => line.startsWith("data: "));
          if (!dataLine) continue;

          // Track the last event ID for reconnection
          if (idLine) {
            this.lastEventId = idLine.slice("id: ".length).trim();
          }

          const raw = dataLine.slice("data: ".length);
          this.rawEvents.push(raw);

          try {
            const event = JSON.parse(raw) as FeedStreamEvent;
            this.events.push(event);
          } catch {
            // Non-JSON event (keep-alive comment, etc.)
          }
        }
      }
    } catch (e: unknown) {
      // AbortError is expected when we close the stream
      if (e instanceof DOMException && e.name === "AbortError") return;
      if (e instanceof Error && e.message.includes("abort")) return;
      throw e;
    }
  }

  /** Wait for at least N feed_update events, with timeout. */
  async waitForEvents(count: number, timeoutMs: number = 5000): Promise<FeedStreamEvent[]> {
    const start = Date.now();
    while (this.events.length < count && Date.now() - start < timeoutMs) {
      await new Promise((resolve) => setTimeout(resolve, 100));
    }
    return [...this.events];
  }

  /** Get all collected events so far. */
  getEvents(): FeedStreamEvent[] {
    return [...this.events];
  }

  /** Get all raw event strings. */
  getRawEvents(): string[] {
    return [...this.rawEvents];
  }

  /** Whether the stream connection was established. */
  isConnected(): boolean {
    return this.connected;
  }

  /** Close the SSE connection. */
  close(): void {
    this.abortController.abort();
    this.connected = false;
  }
}

// ---------------------------------------------------------------------------
// Verification Helpers
// ---------------------------------------------------------------------------

/**
 * Queries observations for a workspace.
 */
export async function getObservations(
  surreal: Surreal,
  workspaceId: string,
  options?: { status?: ObservationStatus; category?: string },
): Promise<Array<{ id: RecordId; text: string; severity: string; status: string; category?: string }>> {
  const workspaceRecord = new RecordId("workspace", workspaceId);
  let query = `SELECT id, text, severity, status, category, created_at FROM observation WHERE workspace = $ws`;
  const params: Record<string, unknown> = { ws: workspaceRecord };

  if (options?.status) {
    query += ` AND status = $status`;
    params.status = options.status;
  }
  if (options?.category) {
    query += ` AND category = $category`;
    params.category = options.category;
  }

  query += ` ORDER BY created_at DESC;`;

  const rows = (await surreal.query(query, params)) as Array<
    Array<{ id: RecordId; text: string; severity: string; status: string; category?: string }>
  >;
  return rows[0] ?? [];
}

/**
 * Queries provisional decisions created by the agent activator.
 */
export async function getActivationDecisions(
  surreal: Surreal,
  workspaceId: string,
): Promise<Array<{ id: RecordId; summary: string; rationale: string; status: string; category?: string }>> {
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const rows = (await surreal.query(
    `SELECT id, summary, rationale, status, category, created_at FROM decision
     WHERE workspace = $ws AND category = "operations" AND inferred_by = "agent_activator"
     ORDER BY created_at DESC;`,
    { ws: workspaceRecord },
  )) as Array<
    Array<{ id: RecordId; summary: string; rationale: string; status: string; category?: string }>
  >;
  return rows[0] ?? [];
}

/**
 * Gets the current feed state via the existing GET endpoint.
 */
export async function getFeedState(
  baseUrl: string,
  workspaceId: string,
  user: TestUser,
): Promise<Record<string, unknown>> {
  const response = await fetchRaw(
    `${baseUrl}/api/workspaces/${workspaceId}/feed`,
    { headers: user.headers },
  );
  if (!response.ok) {
    throw new Error(`Failed to get feed state (${response.status})`);
  }
  return (await response.json()) as Record<string, unknown>;
}

/**
 * Checks whether the agent session has a last_request_at timestamp.
 */
export async function getSessionLastRequestAt(
  surreal: Surreal,
  sessionId: string,
): Promise<string | undefined> {
  const sessionRecord = new RecordId("agent_session", sessionId);
  const rows = (await surreal.query(
    `SELECT last_request_at FROM $sess;`,
    { sess: sessionRecord },
  )) as Array<Array<{ last_request_at?: string }>>;
  return rows[0]?.[0]?.last_request_at;
}

/**
 * Queries agent sessions created by the activator (orchestrator_status = "spawning").
 * These are sessions started by the agent activator when LLM classification
 * matched an agent type to an observation.
 */
export async function getActivatedSessions(
  surreal: Surreal,
  workspaceId: string,
): Promise<Array<{ id: RecordId; agent: string; orchestrator_status: string; triggered_by?: RecordId }>> {
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const rows = (await surreal.query(
    `SELECT id, agent, orchestrator_status, triggered_by, created_at FROM agent_session
     WHERE workspace = $ws AND source = "activator"
     ORDER BY created_at DESC;`,
    { ws: workspaceRecord },
  )) as Array<
    Array<{ id: RecordId; agent: string; orchestrator_status: string; triggered_by?: RecordId }>
  >;
  return rows[0] ?? [];
}

/**
 * Queries meta-observations created by the loop dampener.
 */
export async function getMetaObservations(
  surreal: Surreal,
  workspaceId: string,
): Promise<Array<{ id: RecordId; text: string; category: string }>> {
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const rows = (await surreal.query(
    `SELECT id, text, category, created_at FROM observation
     WHERE workspace = $ws AND source_agent = "agent_activator"
     ORDER BY created_at DESC;`,
    { ws: workspaceRecord },
  )) as Array<Array<{ id: RecordId; text: string; category: string }>>;
  return rows[0] ?? [];
}

import { afterAll, beforeAll, describe, expect, it } from "bun:test";
import { randomUUID } from "node:crypto";
import { RecordId, Surreal } from "surrealdb";
import { applyTestSchema } from "../acceptance-test-kit";

/**
 * Walking Skeleton: Unified Identity Hub-and-Spoke
 *
 * Proves the thinnest vertical slice through the identity model:
 * 1. Identity hub table exists and accepts records
 * 2. Agent spoke table exists and accepts records
 * 3. Spoke edges connect hub to spoke (identity_person, identity_agent)
 * 4. Graph traversal works from identity -> spoke -> spoke record
 *
 * This is the FIRST test to enable. All other unified-identity tests
 * remain skipped until this skeleton passes.
 */

const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";

let surreal: Surreal;
let namespace: string;
let database: string;

let workspaceRecord: RecordId<"workspace", string>;
let personRecord: RecordId<"person", string>;

beforeAll(async () => {
  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
  namespace = `smoke_identity_skeleton_${runId}`;
  database = `skeleton_${Math.floor(Math.random() * 100000)}`;

  surreal = new Surreal();
  await surreal.connect(surrealUrl);
  await surreal.signin({ username: surrealUsername, password: surrealPassword });
  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
  await surreal.use({ namespace });
  await surreal.query(`DEFINE DATABASE ${database};`);
  await surreal.use({ namespace, database });

  await applyTestSchema(surreal);

  const now = new Date();

  // Create workspace
  workspaceRecord = new RecordId("workspace", randomUUID());
  await surreal.create(workspaceRecord).content({
    name: "Identity Skeleton Workspace",
    status: "active",
    onboarding_complete: true,
    onboarding_turn_count: 0,
    onboarding_summary_pending: false,
    onboarding_started_at: now,
    created_at: now,
  });

  // Create person (existing spoke target)
  personRecord = new RecordId("person", randomUUID());
  await surreal.query("CREATE $record CONTENT $content;", {
    record: personRecord,
    content: {
      name: "Marcus Oliveira",
      contact_email: "marcus@conductor.dev",
      created_at: now,
      updated_at: now,
    },
  });
}, 60_000);

afterAll(async () => {
  if (!surreal) return;
  try {
    await surreal.query(`REMOVE DATABASE ${database};`);
    await surreal.query(`REMOVE NAMESPACE ${namespace};`);
  } catch {}
  await surreal.close().catch(() => {});
}, 10_000);

describe("Walking Skeleton: identity hub-and-spoke model delivers unified actor lookup", () => {
  it("Given a workspace with a person, when a human identity hub is created and linked via spoke edge, then traversal from identity reaches the person record", async () => {
    const now = new Date();

    // Create identity hub for human
    const identityRecord = new RecordId("identity", `marcus-human-${randomUUID()}`);
    await surreal.query("CREATE $record CONTENT $content;", {
      record: identityRecord,
      content: {
        name: "Marcus Oliveira",
        type: "human",
        role: "owner",
        workspace: workspaceRecord,
        created_at: now,
      },
    });

    // Create spoke edge: identity -> person
    await surreal.query(
      "RELATE $identity->identity_person->$person SET added_at = $now;",
      { identity: identityRecord, person: personRecord, now },
    );

    // Verify: identity record exists with correct fields
    const [identity] = await surreal.query<
      [Array<{ name: string; type: string; role: string }>]
    >("SELECT name, type, role FROM $record;", { record: identityRecord });
    expect(identity.length).toBe(1);
    expect(identity[0].name).toBe("Marcus Oliveira");
    expect(identity[0].type).toBe("human");
    expect(identity[0].role).toBe("owner");

    // Verify: spoke traversal from identity reaches person
    const [personViaSpoke] = await surreal.query<
      [Array<{ spoke: Array<{ name: string; contact_email: string }> }>]
    >(
      "SELECT ->identity_person->person.{ name, contact_email } AS spoke FROM $record;",
      { record: identityRecord },
    );
    expect(personViaSpoke.length).toBe(1);
    expect(personViaSpoke[0].spoke.length).toBe(1);
    expect(personViaSpoke[0].spoke[0].name).toBe("Marcus Oliveira");
    expect(personViaSpoke[0].spoke[0].contact_email).toBe("marcus@conductor.dev");
  }, 60_000);

  it("Given a human identity exists, when an agent identity is created with managed_by pointing to the human, then the managed_by chain resolves to a human in one hop", async () => {
    const now = new Date();

    // Create human identity (the manager)
    const humanIdentity = new RecordId("identity", `owner-${randomUUID()}`);
    await surreal.query("CREATE $record CONTENT $content;", {
      record: humanIdentity,
      content: {
        name: "Marcus Oliveira",
        type: "human",
        role: "owner",
        workspace: workspaceRecord,
        created_at: now,
      },
    });

    // Create agent spoke
    const agentRecord = new RecordId("agent", `pm-${randomUUID()}`);
    await surreal.query("CREATE $record CONTENT $content;", {
      record: agentRecord,
      content: {
        agent_type: "management",
        runtime: "brain",
        name: "PM Agent",
        model: "claude-sonnet-4-20250514",
        managed_by: humanIdentity,
        created_at: now,
      },
    });

    // Create agent identity hub
    const agentIdentity = new RecordId("identity", `pm-agent-${randomUUID()}`);
    await surreal.query("CREATE $record CONTENT $content;", {
      record: agentIdentity,
      content: {
        name: "PM Agent",
        type: "agent",
        role: "management",
        workspace: workspaceRecord,
        created_at: now,
      },
    });

    // Create spoke edge: identity -> agent
    await surreal.query(
      "RELATE $identity->identity_agent->$agent SET added_at = $now;",
      { identity: agentIdentity, agent: agentRecord, now },
    );

    // Verify: managed_by chain resolves from agent identity to human identity
    const [chain] = await surreal.query<
      [Array<{ managed_by: RecordId; manager_type: string; manager_name: string }>]
    >(
      `SELECT
        ->identity_agent->agent.managed_by AS managed_by,
        ->identity_agent->agent.managed_by.type AS manager_type,
        ->identity_agent->agent.managed_by.name AS manager_name
      FROM $record;`,
      { record: agentIdentity },
    );

    expect(chain.length).toBe(1);
    // managed_by resolves to the human identity in 1 hop
    const managerTypes = chain[0].manager_type as unknown as string[];
    const managerNames = chain[0].manager_name as unknown as string[];
    expect(managerTypes[0]).toBe("human");
    expect(managerNames[0]).toBe("Marcus Oliveira");
  }, 60_000);

  it("Given both human and agent identities exist in a workspace, when querying all identities for the workspace, then both appear with correct types", async () => {
    const now = new Date();

    // Create a fresh pair of identities for this assertion
    const humanId = new RecordId("identity", `ws-human-${randomUUID()}`);
    const agentId = new RecordId("identity", `ws-agent-${randomUUID()}`);

    await surreal.query("CREATE $record CONTENT $content;", {
      record: humanId,
      content: {
        name: "Ana Torres",
        type: "human",
        role: "owner",
        workspace: workspaceRecord,
        created_at: now,
      },
    });

    await surreal.query("CREATE $record CONTENT $content;", {
      record: agentId,
      content: {
        name: "Code Agent",
        type: "agent",
        role: "coder",
        workspace: workspaceRecord,
        created_at: now,
      },
    });

    // Query all identities in workspace
    const [identities] = await surreal.query<
      [Array<{ name: string; type: string; role: string }>]
    >(
      "SELECT name, type, role FROM identity WHERE workspace = $ws;",
      { ws: workspaceRecord },
    );

    const names = identities.map((i) => i.name);
    const types = identities.map((i) => i.type);

    expect(names).toContain("Ana Torres");
    expect(names).toContain("Code Agent");
    expect(types).toContain("human");
    expect(types).toContain("agent");
  }, 60_000);
});

import { afterAll, beforeAll, describe, expect, it } from "bun:test";
import { randomUUID } from "node:crypto";
import { RecordId, Surreal } from "surrealdb";
import { applyTestSchema } from "../acceptance-test-kit";

/**
 * US-UI-005: Dual-Label Audit Trail Query
 *
 * Validates the audit trail queries that return dual-label attribution:
 * - Agent actions show actor identity + accountable human via managed_by chain
 * - Human actions show self as both actor and accountable
 * - Mixed human/agent attribution handled in query results
 * - "Agent suggestions that became tasks" query works with identity references
 * - No unattributed entities in workspace after migration
 */

const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";

let surreal: Surreal;
let namespace: string;
let database: string;
let workspaceRecord: RecordId<"workspace", string>;
let humanIdentity: RecordId<"identity", string>;
let agentIdentity: RecordId<"identity", string>;
let agentRecord: RecordId<"agent", string>;

beforeAll(async () => {
  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
  namespace = `smoke_audit_trail_${runId}`;
  database = `audit_${Math.floor(Math.random() * 100000)}`;

  surreal = new Surreal();
  await surreal.connect(surrealUrl);
  await surreal.signin({ username: surrealUsername, password: surrealPassword });
  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
  await surreal.use({ namespace });
  await surreal.query(`DEFINE DATABASE ${database};`);
  await surreal.use({ namespace, database });

  await applyTestSchema(surreal);

  const now = new Date();

  workspaceRecord = new RecordId("workspace", randomUUID());
  await surreal.create(workspaceRecord).content({
    name: "Audit Trail Test",
    status: "active",
    onboarding_complete: true,
    onboarding_turn_count: 0,
    onboarding_summary_pending: false,
    onboarding_started_at: now,
    created_at: now,
  });

  // Human identity
  humanIdentity = new RecordId("identity", randomUUID());
  await surreal.query("CREATE $record CONTENT $content;", {
    record: humanIdentity,
    content: {
      name: "Marcus Oliveira",
      type: "human",
      role: "owner",
      workspace: workspaceRecord,
      created_at: now,
    },
  });

  // Agent spoke with managed_by
  agentRecord = new RecordId("agent", randomUUID());
  await surreal.query("CREATE $record CONTENT $content;", {
    record: agentRecord,
    content: {
      agent_type: "management",
      runtime: "brain",
      name: "PM Agent",
      model: "claude-sonnet-4-20250514",
      managed_by: humanIdentity,
      created_at: now,
    },
  });

  // Agent identity
  agentIdentity = new RecordId("identity", randomUUID());
  await surreal.query("CREATE $record CONTENT $content;", {
    record: agentIdentity,
    content: {
      name: "PM Agent",
      type: "agent",
      role: "management",
      workspace: workspaceRecord,
      created_at: now,
    },
  });

  // Spoke edge: agent identity -> agent
  await surreal.query(
    "RELATE $identity->identity_agent->$agent SET added_at = $now;",
    { identity: agentIdentity, agent: agentRecord, now },
  );
}, 60_000);

afterAll(async () => {
  if (!surreal) return;
  try {
    await surreal.query(`REMOVE DATABASE ${database};`);
    await surreal.query(`REMOVE NAMESPACE ${namespace};`);
  } catch {}
  await surreal.close().catch(() => {});
}, 10_000);

describe("US-UI-005: Dual-label audit trail shows actor and accountable human for every action", () => {
  // -- Happy path: agent action with dual-label --

  it("Given the PM Agent created a task, when the task's audit trail is queried, then the result shows actor 'PM Agent' with type 'agent' and accountable human 'Marcus Oliveira'", async () => {
    const now = new Date();
    const taskRecord = new RecordId("task", randomUUID());

    await surreal.query("CREATE $record CONTENT $content;", {
      record: taskRecord,
      content: {
        title: "Set up CI pipeline",
        status: "open",
        owner: agentIdentity,
        workspace: workspaceRecord,
        created_at: now,
        updated_at: now,
      },
    });

    // Dual-label query: resolve owner identity and managed_by chain
    // Step 1: get actor identity
    const [actorRows] = await surreal.query<
      [Array<{ title: string; actor_name: string; actor_type: string; owner_id: RecordId }>]
    >(
      `SELECT title, owner.name AS actor_name, owner.type AS actor_type, owner AS owner_id FROM $record;`,
      { record: taskRecord },
    );

    expect(actorRows[0].actor_name).toBe("PM Agent");
    expect(actorRows[0].actor_type).toBe("agent");

    // Step 2: traverse managed_by chain from agent identity
    const [managedByRows] = await surreal.query<
      [Array<{ managed_by_name: string; managed_by_type: string }>]
    >(
      `SELECT ->identity_agent->agent.managed_by.name AS managed_by_name, ->identity_agent->agent.managed_by.type AS managed_by_type FROM $identity;`,
      { identity: actorRows[0].owner_id },
    );

    expect(managedByRows[0].managed_by_name).toContain("Marcus Oliveira");
    expect(managedByRows[0].managed_by_type).toContain("human");
  }, 60_000);

  // -- Human action: self as accountable --

  it("Given Marcus directly created a decision, when the decision's audit trail is queried, then actor and accountable human are both 'Marcus Oliveira'", async () => {
    const now = new Date();
    const decisionRecord = new RecordId("decision", randomUUID());

    await surreal.query("CREATE $record CONTENT $content;", {
      record: decisionRecord,
      content: {
        summary: "Use SurrealDB for graph storage",
        status: "confirmed",
        decided_by: humanIdentity,
        confirmed_by: humanIdentity,
        workspace: workspaceRecord,
        created_at: now,
        updated_at: now,
      },
    });

    const [result] = await surreal.query<
      [Array<{
        actor_name: string;
        actor_type: string;
      }>]
    >(
      `SELECT
        decided_by.name AS actor_name,
        decided_by.type AS actor_type
      FROM $record;`,
      { record: decisionRecord },
    );

    expect(result[0].actor_name).toBe("Marcus Oliveira");
    expect(result[0].actor_type).toBe("human");
    // For human actors, the accountable human is the same person
    // No managed_by chain traversal needed
  }, 60_000);

  // -- Mixed attribution in workspace --

  it("Given both human and agent owned tasks exist, when all tasks are queried with attribution, then each task shows an identity reference with type context", async () => {
    const now = new Date();

    // Human-owned task
    const humanTask = new RecordId("task", randomUUID());
    await surreal.query("CREATE $record CONTENT $content;", {
      record: humanTask,
      content: {
        title: "Review architecture",
        status: "done",
        owner: humanIdentity,
        workspace: workspaceRecord,
        created_at: now,
        updated_at: now,
      },
    });

    // Agent-owned task
    const agentTask = new RecordId("task", randomUUID());
    await surreal.query("CREATE $record CONTENT $content;", {
      record: agentTask,
      content: {
        title: "Generate status report",
        status: "open",
        owner: agentIdentity,
        workspace: workspaceRecord,
        created_at: now,
        updated_at: now,
      },
    });

    const [tasks] = await surreal.query<
      [Array<{
        title: string;
        actor_name: string;
        actor_type: string;
        created_at: string;
      }>]
    >(
      `SELECT
        title,
        owner.name AS actor_name,
        owner.type AS actor_type,
        created_at
      FROM task
      WHERE workspace = $ws AND owner != NONE
      ORDER BY created_at DESC;`,
      { ws: workspaceRecord },
    );

    const types = tasks.map((t) => t.actor_type);
    expect(types).toContain("human");
    expect(types).toContain("agent");

    // Every task with an owner has an identity reference
    for (const task of tasks) {
      expect(task.actor_name).toBeDefined();
      expect(task.actor_type).toBeDefined();
      expect(["human", "agent", "system"]).toContain(task.actor_type);
    }
  }, 60_000);

  // -- No unattributed entities --

  it("Given the unified identity migration is complete, when all tasks with owners are queried, then every owner references an identity record (not person or null)", async () => {
    const [tasks] = await surreal.query<
      [Array<{ title: string; owner: RecordId }>]
    >(
      "SELECT title, owner FROM task WHERE workspace = $ws AND owner != NONE;",
      { ws: workspaceRecord },
    );

    for (const task of tasks) {
      expect(task.owner).toBeDefined();
      expect((task.owner as RecordId).table.name).toBe("identity");
    }
  }, 60_000);

  // -- Suggestion-to-task tracking --

  it("Given the PM Agent created a suggestion that was converted to a task, when the suggestion trail is queried, then the suggestion shows the agent actor and the resulting task", async () => {
    const now = new Date();
    const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

    // Create suggestion by agent
    const suggestionRecord = new RecordId("suggestion", randomUUID());
    await surreal.query("CREATE $record CONTENT $content;", {
      record: suggestionRecord,
      content: {
        text: "Prioritize auth feature",
        category: "opportunity",
        rationale: "Auth blocks other features",
        suggested_by: "PM Agent",
        confidence: 0.9,
        status: "converted",
        workspace: workspaceRecord,
        converted_at: now,
        created_at: thirtyDaysAgo,
        updated_at: now,
      },
    });

    // Create task that was converted from suggestion
    const taskRecord = new RecordId("task", randomUUID());
    await surreal.query("CREATE $record CONTENT $content;", {
      record: taskRecord,
      content: {
        title: "Implement OAuth flow",
        status: "done",
        owner: humanIdentity,
        workspace: workspaceRecord,
        created_at: thirtyDaysAgo,
        updated_at: now,
      },
    });

    // Link suggestion -> task via converted_from edge
    await surreal.query(
      "RELATE $task->converted_from->$suggestion SET converted_at = $now;",
      { task: taskRecord, suggestion: suggestionRecord, now },
    );

    // Update suggestion with converted_to
    await surreal.query(
      "UPDATE $record SET converted_to = $task;",
      { record: suggestionRecord, task: taskRecord },
    );

    // Query: suggestions converted to tasks with their outcomes
    const [results] = await surreal.query<
      [Array<{
        suggestion_text: string;
        suggested_by: string;
        task_title: string;
        task_status: string;
        created_at: string;
      }>]
    >(
      `SELECT
        text AS suggestion_text,
        suggested_by,
        converted_to.title AS task_title,
        converted_to.status AS task_status,
        created_at
      FROM suggestion
      WHERE workspace = $ws AND status = 'converted'
      ORDER BY created_at DESC;`,
      { ws: workspaceRecord },
    );

    expect(results.length).toBeGreaterThan(0);
    const authSuggestion = results.find((r) => r.suggestion_text === "Prioritize auth feature");
    expect(authSuggestion).toBeDefined();
    expect(authSuggestion!.suggested_by).toBe("PM Agent");
    expect(authSuggestion!.task_title).toBe("Implement OAuth flow");
    expect(authSuggestion!.task_status).toBe("done");
  }, 60_000);

  // -- Error/edge case: identity with no managed_by (human) --

  it("Given a human identity has no managed_by chain, when the dual-label query is run, then the managed_by traversal returns empty without error", async () => {
    const now = new Date();
    const taskRecord = new RecordId("task", randomUUID());

    await surreal.query("CREATE $record CONTENT $content;", {
      record: taskRecord,
      content: {
        title: "Human-only task",
        status: "open",
        owner: humanIdentity,
        workspace: workspaceRecord,
        created_at: now,
        updated_at: now,
      },
    });

    // Step 1: get actor identity
    const [actorRows] = await surreal.query<
      [Array<{ actor_type: string; owner_id: RecordId }>]
    >(
      `SELECT owner.type AS actor_type, owner AS owner_id FROM $record;`,
      { record: taskRecord },
    );

    expect(actorRows[0].actor_type).toBe("human");

    // Step 2: traverse managed_by chain -- for human identity, no agent spoke exists
    const [managedByRows] = await surreal.query<
      [Array<{ managed_by_chain: Array<unknown> }>]
    >(
      `SELECT ->identity_agent->agent.managed_by AS managed_by_chain FROM $identity;`,
      { identity: actorRows[0].owner_id },
    );

    // managed_by traversal on a human identity yields empty (no agent spoke)
    expect(managedByRows[0].managed_by_chain).toEqual([]);
  }, 60_000);
});

