  ↓
[anthropic-proxy-route.ts]
  ├→ resolveIdentity() → identity signals
  ├→ resolveSessionId() → session context
  └→ evaluateProxyPolicy(ProxyPolicyContext)
       ↓ [policy-evaluator.ts]
       ├→ loadWorkspacePolicies()
       ├→ evaluateModelAccess(policies, context)
       │   └→ Filter: policies.filter(p => p.selector.agent_role === context.agentType)
       └→ Return: allow | deny_model | deny_budget | deny_rate_limit
  ↓
[MCP Requests Only: mcp/auth.ts]
  ├→ Extract JWT claim "urn:brain:agent_type"
  ├→ Allow override via X-Agent-Type header
