135→        customAccessTokenClaims: async ({ user }) => {
136→          if (!user) return {};
137→          const [memberRows] = await surreal.query<
138→            [Array<{ workspace_id: RecordId<"workspace", string>; workspace_name: string }>]
139→          >(
