  1→/**
  2→ * Identity Resolver — Pure function for extracting identity signals
  3→ * from Claude Code metadata and X-Brain-* headers.
  4→ *
  5→ * Port: (IdentityInput) -> IdentitySignals
  6→ * No IO, no side effects. Pure transformation.
  7→ */
  8→
  9→// ---------------------------------------------------------------------------
 10→// Types
 11→// ---------------------------------------------------------------------------
 12→
 13→export type IdentityInput = {
 14→  metadataUserId?: string;
 15→  workspaceHeader?: string;
 16→  taskHeader?: string;
 17→  agentTypeHeader?: string;
 18→  sessionHeader?: string;
 19→  /** Identity ID resolved from a proxy token (Brain auth mode) */
 20→  proxyTokenIdentityId?: string;
 21→  userAgent?: string;
 22→};
 23→
 24→export type IdentitySignals = {
 25→  userHash?: string;
 26→  accountId?: string;
 27→  sessionId?: string;
 28→  sessionHeaderId?: string;
 29→  workspaceId?: string;
 30→  taskId?: string;
 31→  agentType?: string;
 32→  /** Identity ID from a proxy token (Brain auth mode) */
 33→  proxyTokenIdentityId?: string;
 34→  userAgent?: string;
 35→};
 36→
 37→// ---------------------------------------------------------------------------
 38→// Pure Functions
 39→// ---------------------------------------------------------------------------
 40→
 41→/**
 42→ * Parse Claude Code's metadata.user_id format:
 43→ * "user_<hash>_account_<uuid>_session_<uuid>"
 44→ *
 45→ * Returns extracted fields, or treats the entire string as an opaque user hash
 46→ * when it doesn't match the expected pattern.
 47→ */
 48→function parseMetadataUserId(userId?: string): {
 49→  userHash?: string;
 50→  accountId?: string;
 51→  sessionId?: string;
 52→} {
 53→  if (!userId) return {};
 54→
 55→  const match = userId.match(
 56→    /^user_([\w-]+)_account_([\w-]+)_session_([\w-]+)$/,
 57→  );
 58→
 59→  if (!match) return { userHash: userId };
 60→
 61→  return {
 62→    userHash: match[1],
 63→    accountId: match[2],
 64→    sessionId: match[3],
 65→  };
 66→}
 67→
 68→/**
 69→ * Resolve identity signals from request metadata and headers.
 70→ *
 71→ * Combines Claude Code metadata.user_id parsing with X-Brain-* headers
 72→ * to produce a complete identity picture. Missing signals degrade
 73→ * gracefully — each field is optional.
 74→ */
 75→/**
 76→ * Derive the agent name from identity signals.
 77→ *
 78→ * Priority:
 79→ * 1. X-Brain-Agent-Type header (explicit)
 80→ * 2. User-Agent containing "claude-cli" → "claude-cli"
 81→ * 3. "proxy" (unknown caller)
 82→ */
 83→export function resolveAgentName(signals: Pick<IdentitySignals, "agentType" | "userAgent">): string {
 84→  if (signals.agentType) return signals.agentType;
 85→  if (signals.userAgent?.includes("claude-cli")) return "claude-cli";
 86→  return "proxy";
 87→}
 88→
 89→export function resolveIdentity(input: IdentityInput): IdentitySignals {
 90→  const parsed = parseMetadataUserId(input.metadataUserId);
 91→
 92→  return {
 93→    userHash: parsed.userHash,
 94→    accountId: parsed.accountId,
 95→    sessionId: parsed.sessionId,
 96→    sessionHeaderId: input.sessionHeader,
 97→    workspaceId: input.workspaceHeader,
 98→    taskId: input.taskHeader,
 99→    agentType: input.agentTypeHeader,
100→    proxyTokenIdentityId: input.proxyTokenIdentityId,
101→    userAgent: input.userAgent,
102→  };
103→}
104→

  1→/**
  2→ * Proxy Policy Evaluator — Pre-request policy enforcement
  3→ *
  4→ * Evaluates three policy dimensions before forwarding LLM requests:
  5→ * 1. Model access — agent_type allowed to use requested model
  6→ * 2. Budget enforcement — workspace daily spend within limit
  7→ * 3. Rate limiting — in-memory sliding window per workspace
  8→ *
  9→ * Pure core with effect boundaries at spend queries and observation writes.
 10→ *
 11→ * Port: (ProxyPolicyContext, ProxyPolicyDependencies) -> Promise<ProxyPolicyResult>
 12→ */
 13→
 14→import { RecordId } from "surrealdb";
 15→import type { Surreal } from "surrealdb";
 16→import type { InflightTracker } from "../runtime/types";
 17→import { createObservation } from "../observation/queries";
 18→import { log } from "../telemetry/logger";
 19→import {
 20→  type RateLimiterState,
 21→  checkRateLimit,
 22→} from "./rate-limiter";
 23→
 24→// ---------------------------------------------------------------------------
 25→// Types
 26→// ---------------------------------------------------------------------------
 27→
 28→export type ProxyPolicyContext = {
 29→  readonly workspaceId: string;
 30→  readonly agentType?: string;
