248→// ---------------------------------------------------------------------------
249→// Main Evaluation Pipeline
250→// ---------------------------------------------------------------------------
251→
252→export async function evaluateProxyPolicy(
253→  context: ProxyPolicyContext,
254→  deps: ProxyPolicyDependencies,
255→): Promise<ProxyPolicyResult> {
256→  // Step 1: Rate limit check (in-memory, sub-ms)
257→  if (context.workspaceId) {
258→    const rateLimitResult = checkRateLimit(
259→      deps.rateLimiterState,
260→      context.workspaceId,
261→    );
262→
263→    if (!rateLimitResult.allowed) {
264→      log.info("proxy.policy.rate_limited", "Rate limit exceeded", {
265→        workspace_id: context.workspaceId,
266→        rate_limit_per_minute: rateLimitResult.rateLimitPerMinute,
267→      });
268→
269→      return {
270→        decision: "deny_rate_limit",
271→        status: 429,
272→        body: {
273→          error: "rate_limit_exceeded",
274→          rate_limit_per_minute: rateLimitResult.rateLimitPerMinute,
275→          reset_time_unix: rateLimitResult.resetTimeUnix,
276→          remediation: `Rate limit of ${rateLimitResult.rateLimitPerMinute} requests per minute exceeded. Wait ${rateLimitResult.retryAfterSeconds} seconds before retrying.`,
277→        },
278→        retryAfterSeconds: rateLimitResult.retryAfterSeconds,
279→      };
280→    }
281→  }
282→
283→  // Step 2: Budget check (cached DB query)
284→  if (context.workspaceId) {
285→    const dailyBudget = await getDailyBudget(deps.surreal, context.workspaceId);
286→    if (dailyBudget !== undefined) {
287→      const currentSpend = await getTodaySpend(deps.surreal, context.workspaceId, deps.spendCache);
288→      if (currentSpend >= dailyBudget) {
289→        const now = new Date();
290→        const resetSeconds = secondsUntilMidnightUtc(now);
291→
292→        log.info("proxy.policy.budget_exceeded", "Daily budget exceeded", {
293→          workspace_id: context.workspaceId,
294→          current_spend_usd: currentSpend,
295→          daily_limit_usd: dailyBudget,
296→        });
297→
298→        return {
299→          decision: "deny_budget",
300→          status: 429,
301→          body: {
302→            error: "budget_exceeded",
303→            current_spend_usd: currentSpend,
304→            daily_limit_usd: dailyBudget,
305→            time_until_reset_seconds: resetSeconds,
306→            remediation: `Daily budget of $${dailyBudget.toFixed(2)} exceeded. Current spend: $${currentSpend.toFixed(2)}. Budget resets at midnight UTC (${resetSeconds}s).`,
307→          },
308→        };
309→      }
310→    }
311→  }
312→
313→  // Step 3: Model access policy check (DB + pure evaluation)
314→  if (context.workspaceId) {
315→    const policies = await loadWorkspacePolicies(deps.surreal, context.workspaceId);
316→
317→    if (policies.length === 0) {
318→      // No policies: permissive default with async warning (deduplicated per-process via Set)
319→      if (!deps.noPolicyWarnedWorkspaces.has(context.workspaceId)) {
320→        deps.noPolicyWarnedWorkspaces.add(context.workspaceId);
321→        const workspaceRecord = new RecordId("workspace", context.workspaceId);
322→        deps.inflight.track(
323→          createObservation({
324→            surreal: deps.surreal,
325→            workspaceRecord,
326→            text: `No LLM proxy policies configured for workspace. All requests are being forwarded without model access restrictions. Consider creating policies to control which models each agent type can use.`,
327→            severity: "warning",
328→            observationType: "missing",
329→            sourceAgent: "llm-proxy",
330→            now: new Date(),
331→          }).catch((error) => {
332→            log.error("proxy.policy.observation_failed", "Failed to create no-policy warning", error);
333→            return undefined as any;
334→          }),
335→        );
336→      }
337→
338→      return { decision: "allow", policyIds: [] };
339→    }
340→
341→    const modelCheck = evaluateModelAccess(policies, context);
342→
343→    if (!modelCheck.allowed) {
344→      log.info("proxy.policy.model_denied", "Model access denied by policy", {
345→        workspace_id: context.workspaceId,
346→        agent_type: context.agentType,
347→        model: context.model,
348→        policy_ref: modelCheck.policyRef,
349→      });
350→
351→      return {
352→        decision: "deny_model",
353→        status: 403,
354→        body: {
355→          error: "policy_violation",
356→          policy_ref: modelCheck.policyRef,
357→          policy_description: modelCheck.policyDescription,
358→          model_requested: context.model,
359→          model_suggestion: modelCheck.allowedModels,
360→          remediation: `Model '${context.model}' is not allowed for agent type '${context.agentType}'. Allowed models: ${modelCheck.allowedModels.join(", ")}. Contact workspace admin to update model access policies.`,
361→        },
362→      };
363→    }
364→
365→    return { decision: "allow", policyIds: modelCheck.policyIds };
366→  }
367→
368→  // No workspace: permissive (degraded mode)
369→  return { decision: "allow", policyIds: [] };
370→}
