 73→
 74→async function create<T extends string>(
 75→  db: Surreal,
 76→  table: T,
 77→  content: Record<string, unknown>,
 78→  id?: string,
 79→): Promise<Ref<T>> {
 80→  const recordId = id ?? crypto.randomUUID();
 81→  const record = new RecordId(table, recordId);
 82→  await db.query(`CREATE $record CONTENT $content;`, { record, content });
 83→  return { id: recordId, record };
 84→}
 85→
 86→async function relate(
 87→  db: Surreal,
 88→  from: RecordId,
 89→  edge: string,
 90→  to: RecordId,
 91→  fields: Record<string, unknown> = {},
 92→): Promise<void> {
 93→  const bindings: Record<string, unknown> = { from, to, ...fields };
 94→  const setClause = Object.keys(fields).length
 95→    ? " SET " + Object.keys(fields).map((k) => `${k} = $${k}`).join(", ")
 96→    : "";
 97→  await db.query(`RELATE $from->${edge}->$to${setClause};`, bindings);
 98→}
