103→// ---------------------------------------------------------------------------
104→// Workspace Validation (cached)
105→// ---------------------------------------------------------------------------
106→
107→type WorkspaceCache = Map<string, { valid: boolean; checkedAt: number }>;
108→
109→const WORKSPACE_CACHE_TTL_MS = 60_000; // 1 minute
110→
111→async function validateWorkspace(
112→  surreal: ServerDependencies["surreal"],
113→  workspaceId: string,
114→  cache: WorkspaceCache,
115→): Promise<boolean> {
116→  const cached = cache.get(workspaceId);
117→  if (cached && Date.now() - cached.checkedAt < WORKSPACE_CACHE_TTL_MS) {
118→    return cached.valid;
119→  }
120→
121→  try {
122→    const results = await surreal.query<[Array<{ id: RecordId }>]>(
123→      `SELECT id FROM $ws;`,
124→      { ws: new RecordId("workspace", workspaceId) },
125→    );
126→    const valid = (results[0]?.length ?? 0) > 0;
127→    cache.set(workspaceId, { valid, checkedAt: Date.now() });
128→    return valid;
129→  } catch {
130→    cache.set(workspaceId, { valid: false, checkedAt: Date.now() });
131→    return false;
132→  }
133→}
