143→// ---------------------------------------------------------------------------
144→// Header Forwarding
145→// ---------------------------------------------------------------------------
146→
147→export function buildUpstreamHeaders(request: Request, authMode: AuthMode): Headers {
148→  const headers = new Headers();
149→
150→  for (const name of FORWARDED_HEADERS) {
151→    const value = request.headers.get(name);
152→    if (value) headers.set(name, value);
153→  }
154→
155→  if (authMode.mode === "brain" && authMode.serverApiKey) {
156→    // Brain auth with server-held API key: inject it, do not forward client auth
157→    headers.set("x-api-key", authMode.serverApiKey);
158→  } else {
159→    // Direct auth: forward client's auth headers as-is
160→    const xApiKey = request.headers.get("x-api-key");
161→    const authHeader = request.headers.get("authorization");
162→    if (xApiKey) headers.set("x-api-key", xApiKey);
163→    if (authHeader) headers.set("authorization", authHeader);
164→  }
165→
166→  return headers;
167→}
