 37→const ACTOR_DEFAULT_AGENT_TYPE: Partial<Record<string, AgentType>> = {
 38→  pm_agent: "management",
 39→  analytics_agent: "observer",
 40→};
 41→
 42→export async function checkAuthority(input: {
 43→  surreal: Surreal;
 44→  agentType: AgentType;
 45→  action: AuthorityAction;
 46→  workspaceRecord?: RecordId<"workspace", string>;
 47→  identityRecord?: RecordId<"identity", string>;
 48→}): Promise<AuthorityPermission> {
 49→  // 0. Human bypass: if identity type is human, always allow
 50→  if (input.identityRecord) {
 51→    const [identityRows] = await input.surreal.query<[Array<{ type: string }>]>(
 52→      "SELECT type FROM $record;",
 53→      { record: input.identityRecord },
 54→    );
 55→
 56→    if (identityRows.length > 0 && identityRows[0].type === "human") {
 57→      return "auto";
 58→    }
 59→
 60→    // 1. Per-identity permission via authorized_to relation
 61→    const [overrideRows] = await input.surreal.query<[Array<{ permission: string }>]>(
 62→      `SELECT permission FROM authorized_to
 63→       WHERE in = $identity
 64→       AND out.action = $action
 65→       LIMIT 1;`,
 66→      { identity: input.identityRecord, action: input.action },
 67→    );
 68→
 69→    if (overrideRows.length > 0) {
 70→      return overrideRows[0].permission as AuthorityPermission;
 71→    }
 72→  }
 73→
 74→  // 2. Fall back to global default from authority_scope
 75→  const [globalRows] = await input.surreal.query<[Array<{ permission: string }>]>(
 76→    "SELECT permission FROM authority_scope WHERE action = $action AND workspace IS NONE LIMIT 1;",
 77→    { action: input.action },
 78→  );
 79→
 80→  if (globalRows.length > 0) {
 81→    return globalRows[0].permission as AuthorityPermission;
 82→  }
 83→
 84→  // 3. Fail-safe: no row = blocked
 85→  return "blocked";
 86→}
 87→
 88→export async function requireAuthorizedContext(
 89→  options: ToolExecutionOptions,
 90→  action: AuthorityAction,
 91→  deps: { surreal: Surreal },
 92→): Promise<AuthorizedContext> {
 93→  const context = requireToolContext(options);
 94→
 95→  // Contract: MCP contexts must never claim human presence
 96→  if (context.humanPresent && context.actor === "mcp") {
 97→    throw new Error("Contract violation: humanPresent must not be true for MCP contexts");
 98→  }
 99→
100→  // Human-present web sessions bypass authority (human IS the authority)
101→  if (context.humanPresent) {
102→    return { context, permission: "auto" };
103→  }
104→
105→  const agentType: AgentType =
106→    context.agentType ?? ACTOR_DEFAULT_AGENT_TYPE[context.actor] ?? "code_agent";
107→
108→  const permission = await checkAuthority({
109→    surreal: deps.surreal,
110→    agentType,
111→    action,
112→    workspaceRecord: context.workspaceRecord,
113→  });
114→
115→  if (permission === "blocked") {
116→    throw new AuthorityError("blocked", action, agentType);
117→  }
118→
119→  if (permission === "propose") {
120→    throw new AuthorityError("propose", action, agentType);
121→  }
122→
123→  // "auto" or "provisional" — caller proceeds (may mark output as provisional)
124→  return { context, permission };
125→}
126→
127→export function checkAuthorityOrError(
128→  permission: AuthorityPermission,
129→  action: AuthorityAction,
130→  actorLabel: string,
131→): Response | undefined {
132→  if (permission === "blocked") {
133→    return jsonError(`${actorLabel} is not authorized for action: ${action}`, 403);
134→  }
135→  if (permission === "propose") {
136→    return jsonError(
137→      `${actorLabel} can only propose ${action} — requires human approval`,
138→      403,
139→    );
140→  }
141→  return undefined;
142→}
