 32→function createStubSurreal(policies: Array<{
 33→  id: string;
 34→  title: string;
 35→  description?: string;
 36→  agentRole?: string;
 37→  rules: Array<{
 38→    id: string;
 39→    effect: "allow" | "deny";
 40→    priority: number;
 41→    condition: { field: string; operator: string; value: unknown };
 42→  }>;
 43→}>, options?: { dailyBudget?: number; todaySpend?: number }) {
 44→  return {
 45→    query: async (sql: string, params?: Record<string, unknown>) => {
 46→      // loadWorkspacePolicies
 47→      if (sql.includes("FROM policy WHERE")) {
 48→        return [policies.map((p) => ({
 49→          id: new RecordId("policy", p.id),
 50→          title: p.title,
 51→          description: p.description,
 52→          selector: { agent_role: p.agentRole },
 53→          rules: p.rules,
 54→          status: "active",
 55→        }))];
 56→      }
 57→      // getDailyBudget
 58→      if (sql.includes("daily_budget_usd")) {
 59→        return [[{ daily_budget_usd: options?.dailyBudget }]];
 60→      }
 61→      // getTodaySpend
 62→      if (sql.includes("math::sum")) {
 63→        return [[{ total: options?.todaySpend ?? 0 }]];
 64→      }
 65→      // createNoPolicyWarning (observation)
 66→      if (sql.includes("CREATE $obs")) {
 67→        return [[]];
 68→      }
 69→      return [[]];
 70→    },
 71→  } as unknown as import("surrealdb").Surreal;
 72→}
