 1→-- 0017_identity_hub_spoke.surql
 2→-- US-UI-001: Identity hub-spoke schema
 3→-- Creates identity hub, agent spoke, identity_person and identity_agent relation tables.
 4→-- Removes person.identities field (redundant with account table).
 5→
 6→BEGIN TRANSACTION;
 7→
 8→-- Identity hub table
 9→DEFINE TABLE OVERWRITE identity SCHEMAFULL;
10→DEFINE FIELD name ON identity TYPE string;
11→DEFINE FIELD type ON identity TYPE string ASSERT $value IN ['human', 'agent', 'system'];
12→DEFINE FIELD role ON identity TYPE option<string>;
13→DEFINE FIELD workspace ON identity TYPE record<workspace>;
14→DEFINE FIELD created_at ON identity TYPE datetime;
15→
16→-- B-tree indexes for identity lookup
17→DEFINE INDEX identity_workspace ON identity FIELDS workspace;
18→DEFINE INDEX identity_type_workspace ON identity FIELDS type, workspace;
19→
20→-- Agent spoke table
21→DEFINE TABLE OVERWRITE agent SCHEMAFULL;
22→DEFINE FIELD agent_type ON agent TYPE string ASSERT $value IN ['code_agent', 'architect', 'management', 'design_partner', 'observer', 'chat_agent', 'mcp'];
23→DEFINE FIELD model ON agent TYPE option<string>;
24→DEFINE FIELD managed_by ON agent TYPE record<identity>;
25→DEFINE FIELD created_at ON agent TYPE datetime;
26→
27→-- Spoke edge: identity -> person
28→DEFINE TABLE OVERWRITE identity_person TYPE RELATION IN identity OUT person SCHEMAFULL;
29→DEFINE FIELD added_at ON identity_person TYPE datetime;
30→
31→-- Spoke edge: identity -> agent
32→DEFINE TABLE OVERWRITE identity_agent TYPE RELATION IN identity OUT agent SCHEMAFULL;
33→DEFINE FIELD added_at ON identity_agent TYPE datetime;
34→
35→-- Remove person.identities field (redundant with account table)
36→REMOVE FIELD identities ON person;
37→REMOVE FIELD identities[*].provider ON person;
38→REMOVE FIELD identities[*].id ON person;
39→
40→COMMIT TRANSACTION;
