import { RecordId, type Surreal } from "surrealdb";
import { jsonError } from "../http/response";
import { createJwtValidator, type BrainTokenClaims } from "./token-validation";
import type { McpAuthResult } from "./types";

type WorkspaceRow = {
  id: RecordId<"workspace", string>;
  name: string;
};

const validatorsByIssuer = new Map<string, (token: string) => Promise<BrainTokenClaims>>();

/**
 * Authenticate an MCP request via OAuth 2.1 JWT Bearer token.
 * Validates the JWT signature via JWKS, extracts claims, and verifies workspace access.
 * Returns auth context on success, or an error Response.
 */
export async function authenticateMcpRequest(
  request: Request,
  workspaceId: string,
  surreal: Surreal,
  issuerUrl: string,
): Promise<McpAuthResult | Response> {
  const authHeader = request.headers.get("authorization");
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    return jsonError("missing or invalid Authorization header", 401);
  }

  const token = authHeader.slice(7);
  if (!token) {
    return jsonError("empty Bearer token", 401);
  }

  // Get or create a JWT validator for this issuer URL (safe for concurrent test suites)
  let validateToken = validatorsByIssuer.get(issuerUrl);
  if (!validateToken) {
    validateToken = createJwtValidator(issuerUrl);
    validatorsByIssuer.set(issuerUrl, validateToken);
  }

  let claims: BrainTokenClaims;
  try {
    claims = await validateToken(token);
  } catch (err) {
    const detail = err instanceof Error ? err.message : String(err);
    console.error(`[MCP Auth] JWT validation failed: ${detail}`);
    return jsonError("invalid or expired token", 401);
  }

  // Extract person from sub claim (better-auth user model is person)
  const personId = claims.sub;
  if (!personId) {
    return jsonError("token missing sub claim", 401);
  }

  // Extract workspace from custom claim or verify against requested workspace
  const claimedWorkspace = claims["urn:brain:workspace"];
  if (claimedWorkspace && claimedWorkspace !== workspaceId) {
    return jsonError("token workspace does not match requested workspace", 403);
  }

  // Verify workspace exists
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const workspace = await surreal.select<WorkspaceRow>(workspaceRecord);
  if (!workspace) {
    return jsonError("workspace not found", 404);
  }

  // Resolve identity from person via spoke edge
  const personRecord = new RecordId("person", personId);
  const [identityRows] = await surreal.query<[Array<RecordId<"identity", string>>]>(
    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
    { person: personRecord },
  );
  const identityRecord = identityRows[0];
  if (!identityRecord) {
    return jsonError("identity not found for token owner", 403);
  }

  // If no workspace claim in token, verify membership via DB
  if (!claimedWorkspace) {
    const [memberRows] = await surreal.query<[Array<{ role: string }>]>(
      `SELECT role FROM member_of WHERE in = $identity AND out = $ws LIMIT 1;`,
      { identity: identityRecord, ws: workspaceRecord },
    );
    if (!memberRows || memberRows.length === 0) {
      return jsonError("token owner is not a member of this workspace", 403);
    }
  }

  // Extract scopes from token
  const scopeString = claims.scope ?? "";
  const scopes = new Set(scopeString.split(" ").filter(Boolean));

  // Agent name from header (free-form string, no closed-set validation)
  const agentName = request.headers.get("x-agent-type") ?? "code_agent";

  return {
    workspaceRecord,
    workspaceName: workspace.name,
    agentType: agentName,
    identityRecord,
    scopes,
    humanPresent: false as const,
  };
}

import { describe, expect, it, beforeAll, afterAll } from "bun:test";
import { RecordId, Surreal } from "surrealdb";
import { applyTestSchema } from "../acceptance-test-kit";
import { checkAuthority } from "../../../app/src/server/iam/authority";
import { resolveByEmail } from "../../../app/src/server/iam/identity";
import { resolveWorkspaceIdentity } from "../../../app/src/server/extraction/identity-resolution";

const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";

let surreal: Surreal;
let namespace: string;
let database: string;

beforeAll(async () => {
  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
  namespace = `smoke_auth_${runId}`;
  database = `authority_${Math.floor(Math.random() * 100000)}`;

  surreal = new Surreal();
  await surreal.connect(surrealUrl);
  await surreal.signin({ username: surrealUsername, password: surrealPassword });
  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
  await surreal.use({ namespace });
  await surreal.query(`DEFINE DATABASE ${database};`);
  await surreal.use({ namespace, database });

  // Apply base schema (canonical full schema — migrations are for evolving existing DBs)
  await applyTestSchema(surreal);
}, 30_000);

afterAll(async () => {
  if (!process.env.SMOKE_KEEP_DB) {
    try {
      await surreal.query(`REMOVE DATABASE ${database};`);
    } catch {}
    try {
      await surreal.query(`REMOVE NAMESPACE ${namespace};`);
    } catch {}
  }
  surreal.close();
});

describe("checkAuthority", () => {
  it("returns global default for create_task (auto)", async () => {
    const result = await checkAuthority({
      surreal,
      agentType: "code_agent",
      action: "create_task",
    });
    expect(result).toBe("auto");
  });

  it("returns global default for confirm_decision (blocked)", async () => {
    const result = await checkAuthority({
      surreal,
      agentType: "code_agent",
      action: "confirm_decision",
    });
    expect(result).toBe("blocked");
  });

  it("returns global default for create_decision (provisional)", async () => {
    const result = await checkAuthority({
      surreal,
      agentType: "code_agent",
      action: "create_decision",
    });
    expect(result).toBe("provisional");
  });

  it("returns global default for create_observation (auto)", async () => {
    const result = await checkAuthority({
      surreal,
      agentType: "observer",
      action: "create_observation",
    });
    expect(result).toBe("auto");
  });

  it("returns blocked for unknown action", async () => {
    const result = await checkAuthority({
      surreal,
      agentType: "code_agent",
      // @ts-expect-error — testing unknown action fallback
      action: "nonexistent_action",
    });
    expect(result).toBe("blocked");
  });

  it("per-identity authorized_to edge overrides global default", async () => {
    const workspaceRecord = new RecordId("workspace", "test-ws-override");
    await surreal.create(workspaceRecord).content({
      name: "test-override",
      status: "active",
      created_at: new Date(),
      updated_at: new Date(),
      onboarding_complete: true,
      onboarding_turn_count: 0,
      onboarding_summary_pending: false,
      onboarding_started_at: new Date(),
    });

    // Global default for confirm_decision is blocked
    const globalResult = await checkAuthority({
      surreal,
      agentType: "code_agent",
      action: "confirm_decision",
